2	
3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	const LOYALTY_YEARS_THRESHOLD = 2;
26	
27	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	  moonstone: 25,
34	};
35	
36	function groupByType(items: Item[]): Map<string, Item[]> {
37	  const groups = new Map<string, Item[]>();
38	  for (const item of items) {
39	    const group = groups.get(item.type) ?? [];
40	    group.push(item);
41	    groups.set(item.type, group);
42	  }
43	  return groups;
44	}
45	
46	function premiumForGroup(type: string, group: Item[]): number {
47	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
48	    return COMPONENT_BLOCK_PREMIUM;
49	  }
50	  return group.length * BASE_PREMIUM_BY_TYPE[type];
51	}
52	
53	function itemPremium(item: Item): number {
54	  const base = BASE_PREMIUM_BY_TYPE[item.type];
55	  let premium = base;
56	  if (item.cursed) {
57	    premium += base * CURSE_SURCHARGE_RATE;
58	  }
59	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
60	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
61	  }
62	  return premium;
63	}
64	
65	function hasCursedItem(items: Item[]): boolean {
66	  return items.some((item) => item.cursed);
67	}
68	
69	function hasHighEnchantmentItem(items: Item[]): boolean {
70	  return items.some(
71	    (item) => item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
72	  );
73	}
74	
75	function hasItemModifier(items: Item[]): boolean {
76	  return hasCursedItem(items) || hasHighEnchantmentItem(items);
77	}
78	
79	function baseTotalForItems(items: Item[]): number {
80	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
81	}
82	
83	function premiumForItems(items: Item[]): number {
84	  if (hasItemModifier(items)) {
85	    return items.reduce((sum, item) => sum + itemPremium(item), 0);
86	  }
87	  let total = 0;
88	  for (const [type, group] of groupByType(items)) {
89	    total += premiumForGroup(type, group);
90	  }
91	  return total;
92	}
93	
94	function isFirstContract(input: QuoteInput): boolean {
95	  return input.customerYears === 0 && input.previousContracts === 0;
96	}
97	
98	export function quote(input: QuoteInput): number {
99	  let premium = premiumForItems(input.items);
100	  if (hasItemModifier(input.items) && isFirstContract(input)) {
101	    premium += baseTotalForItems(input.items) * FIRST_INSURANCE_SURCHARGE_RATE;
102	  }
103	  if (input.customerYears >= LOYALTY_YEARS_THRESHOLD) {
104	    premium -= premium * LOYALTY_DISCOUNT_RATE;
105	  }
106	  return premium + PROCESSING_FEE;
107	}
